<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', Arial, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    flex-direction: column;
  }
  h1 {
    font-size: 3rem;
    margin-bottom: 0.25rem;
    letter-spacing: 0.1em;
    color: #f0e68c;
  }
  #score {
    font-size: 1.4rem;
    margin-bottom: 1rem;
    background: #16213e;
    padding: 0.4rem 1.5rem;
    border-radius: 6px;
    border: 1px solid #0f3460;
  }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(4, 1fr);
    gap: 8px;
    background: #16213e;
    padding: 10px;
    border-radius: 10px;
    border: 2px solid #0f3460;
    width: 420px;
    height: 420px;
  }
  .tile {
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 2rem;
    font-weight: bold;
    border-radius: 6px;
    background: #0f3460;
    color: #eee;
    transition: transform 0.1s ease;
  }
  .tile[data-value="2"]   { background: #2a2a4a; }
  .tile[data-value="4"]   { background: #3a3a5a; }
  .tile[data-value="8"]   { background: #e94560; color: #fff; }
  .tile[data-value="16"]  { background: #c23616; color: #fff; }
  .tile[data-value="32"]  { background: #e94560; color: #fff; font-size: 1.8rem; }
  .tile[data-value="64"]  { background: #c23616; color: #fff; font-size: 1.8rem; }
  .tile[data-value="128"] { background: #f0e68c; color: #1a1a2e; font-size: 1.6rem; }
  .tile[data-value="256"] { background: #ffd700; color: #1a1a2e; font-size: 1.6rem; }
  .tile[data-value="512"] { background: #f0e68c; color: #1a1a2e; font-size: 1.4rem; }
  .tile[data-value="1024"]{ background: #ffd700; color: #1a1a2e; font-size: 1.2rem; }
  .tile[data-value="2048"]{ background: #ff6b35; color: #fff; font-size: 1.2rem; }
  #reset {
    margin-top: 1rem;
    padding: 0.6rem 2rem;
    font-size: 1rem;
    border: none;
    border-radius: 6px;
    background: #e94560;
    color: #fff;
    cursor: pointer;
    letter-spacing: 0.05em;
  }
  #reset:hover { background: #c23616; }
</style>
</head>
<body>

<h1>2048</h1>
<div id="score">Score: <span id="score-val">0</span></div>
<div id="board"></div>
<button id="reset">New Game</button>

<script>
(function() {
  const SIZE = 4;
  let board = [];
  let scoreVal = 0;

  function createTile(val) {
    const el = document.createElement('div');
    el.className = 'tile';
    el.setAttribute('data-value', val);
    el.textContent = val === 0 ? '' : val;
    return el;
  }

  function render() {
    const boardEl = document.getElementById('board');
    boardEl.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        boardEl.appendChild(createTile(board[r][c]));
      }
    }
    document.getElementById('score-val').textContent = scoreVal;
  }

  function cloneBoard(b) {
    return b.map(row => [...row]);
  }

  function isEmpty(a, b) {
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (a[r][c] !== b[r][c]) return false;
    return true;
  }

  function slideLine(line) {
    // line is an array of 4 numbers, moving toward index 0
    // Step 1: remove zeros
    let compact = line.filter(v => v !== 0);
    // Step 2: merge adjacent equal pairs from the front
    let merged = [];
    let scored = 0;
    let i = 0;
    while (i < compact.length) {
      if (i + 1 < compact.length && compact[i] === compact[i + 1]) {
        let val = compact[i] * 2;
        merged.push(val);
        scored += val;
        i += 2;
      } else {
        merged.push(compact[i]);
        i++;
      }
    }
    // Step 3: pad with zeros to size
    while (merged.length < SIZE) merged.push(0);
    return { line: merged, score: scored };
  }

  function move(direction) {
    let oldBoard = cloneBoard(board);
    let totalScoreAdd = 0;

    if (direction === 'left' || direction === 'right') {
      for (let r = 0; r < SIZE; r++) {
        let row = [...board[r]];
        if (direction === 'right') row.reverse();
        let result = slideLine(row);
        totalScoreAdd += result.score;
        let newRow = result.line;
        if (direction === 'right') newRow.reverse();
        board[r] = newRow;
      }
    } else {
      // up or down — work on columns
      for (let c = 0; c < SIZE; c++) {
        let col = [];
        for (let r = 0; r < SIZE; r++) col.push(board[r][c]);
        if (direction === 'down') col.reverse();
        let result = slideLine(col);
        totalScoreAdd += result.score;
        let newCol = result.line;
        if (direction === 'down') newCol.reverse();
        for (let r = 0; r < SIZE; r++) board[r][c] = newCol[r];
      }
    }

    scoreVal += totalScoreAdd;

    if (!isEmpty(oldBoard, board)) {
      spawnTile();
    }

    render();
    return !isEmpty(oldBoard, board);
  }

  function spawnTile() {
    let empty = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (board[r][c] === 0) empty.push([r, c]);
    if (empty.length === 0) return;
    let [r, c] = empty[Math.floor(Math.random() * empty.length)];
    board[r][c] = Math.random() < 0.9 ? 2 : 4;
  }

  function resetGame() {
    board = Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
    scoreVal = 0;
    // Start with exactly 2 tiles
    spawnTile();
    spawnTile();
    render();
  }

  function setBoard(arr) {
    board = arr.map(row => [...row]);
    render();
  }

  window.game = {
    get size() { return SIZE; },
    reset: resetGame,
    move: move,
    board: function() { return cloneBoard(board); },
    setBoard: setBoard,
    score: function() { return scoreVal; }
  };

  document.addEventListener('keydown', function(e) {
    const map = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down'
    };
    if (map[e.key]) {
      e.preventDefault();
      window.game.move(map[e.key]);
    }
  });

  document.getElementById('reset').addEventListener('click', function() {
    window.game.reset();
  });

  // Initialize
  resetGame();
})();
</script>
</body>
</html>
